const { Pool } = require('pg');

// Create a new pool instance with connection details
const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'your_database_name',
  password: 'your_password',
  port: 5432,
});

// Function to handle errors
function handleError(err) {
  console.error('Error executing query', err.stack);
}

// CREATE operation for a table named 'users'
async function createUser(user) {
  const query = `INSERT INTO users (name, email) VALUES ($1, $2) RETURNING *`;
  try {
    const res = await pool.query(query, [user.name, user.email]);
    console.log('User created:', res.rows[0]);
  } catch (err) {
    handleError(err);
  }
}

// READ operation for a table named 'users'
async function getUsers() {
  const query = `SELECT * FROM users`;
  try {
    const res = await pool.query(query);
    console.log('Users:', res.rows);
  } catch (err) {
    handleError(err);
  }
}

// UPDATE operation for a table named 'users'
async function updateUser(userId, user) {
  const query = `UPDATE users SET name=$1, email=$2 WHERE id=$3 RETURNING *`;
  try {
    const res = await pool.query(query, [user.name, user.email, userId]);
    console.log('User updated:', res.rows[0]);
  } catch (err) {
    handleError(err);
  }
}

// DELETE operation for a table named 'users'
async function deleteUser(userId) {
  const query = `DELETE FROM users WHERE id=$1`;
  try {
    await pool.query(query, [userId]);
    console.log('User deleted with ID:', userId);
  } catch (err) {
    handleError(err);
  }
}

// Example usage
(async () => {
  // Create a new user
  await createUser({ name: 'John Doe', email: 'john.doe@example.com' });

  // Get all users
  await getUsers();

  // Update a user
  await updateUser(1, { name: 'Jane Doe', email: 'jane.doe@example.com' });

  // Delete a user
  await deleteUser(1);

  // Close the pool connection
  pool.end();
})();